use std::{
    path::{Path, PathBuf},
    time::UNIX_EPOCH,
};

#[derive(Debug, Clone)]
pub struct GenerateConfig {
    // Root Slint directory to write the generated files to
    pub root_slint: PathBuf,
    // Rust OUT_DIR
    pub out_dir: PathBuf,
}

#[derive(Debug, Clone, Eq, PartialEq)]
pub struct GeneratedFile {
    pub path: PathBuf,
    pub content: String,
}

impl GeneratedFile {
    pub fn write(&self, dir: &Path) -> Result<(), std::io::Error> {
        use std::io::Write;

        let path = dir.join(&self.path);
        if let Some(parent) = path.parent() {
            if !parent.exists() {
                std::fs::create_dir_all(parent)?;
            }
        }

        if path.exists() {
            if let Err(e) = std::fs::remove_file(&path) {
                // If this fails it means we have some weird junk in the generated directories, like symlinks
                // or subdirectories, which shouldn't happen. In these cases just let the user
                // clean up manually.
                eprintln!("Could not clean up path '{}' from generated directory: {e:?}", path.display());
                return Err(e);
            }
        }

        let mut file = std::fs::OpenOptions::new().write(true).create(true).truncate(true).open(&path)?;

        file.write_all(PREFIX.as_bytes())?;
        file.write_all(b"\n")?;

        file.write_all(self.content.as_bytes())?;
        file.flush()?;

        // Opt out of file modification detection in cargo
        file.set_modified(UNIX_EPOCH)?;
        // temp fix for the parent directory.
        if let Some(parent) = path.parent() {
            if let Ok(file) = std::fs::File::open(parent) {
                file.set_modified(UNIX_EPOCH)?;
            }
        }

        Ok(())
    }
}

static PREFIX: &str = indoc::indoc! {
"
// Generated by `slint-keyos-platform` DO NOT EDIT!
"
};
